const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;
const nom = body.nom;
const description = body.description || '';
const typeRule = body.typeRule || 'static'; // static | ai_override
const conditions = body.conditions || {};
const actionType = body.actionType || 'auto_reply'; // auto_reply | queue_human | ignore | forward
const actionConfig = body.actionConfig || {};
const priorite = body.priorite || 100;

if (!tenantId || !nom) {
  return [{ json: { success: false, error: 'tenantId et nom requis' } }];
}

return [{ json: { tenantId, nom, description, typeRule, conditions, actionType, actionConfig, priorite } }];

const body = $input.first().json.body || $input.first().json;
const sets = [];
if (body.nom !== undefined) sets.push(`nom = '${body.nom.replace(/'/g, "''")}'`);
if (body.description !== undefined) sets.push(`description = '${body.description.replace(/'/g, "''")}'`);
if (body.conditions !== undefined) sets.push(`conditions = '${JSON.stringify(body.conditions).replace(/'/g, "''")}'::jsonb`);
if (body.actionType !== undefined) sets.push(`action_type = '${body.actionType}'`);
if (body.actionConfig !== undefined) sets.push(`action_config = '${JSON.stringify(body.actionConfig).replace(/'/g, "''")}'::jsonb`);
if (body.priorite !== undefined) sets.push(`priorite = ${body.priorite}`);
if (body.actif !== undefined) sets.push(`actif = ${body.actif}`);
sets.push(`updated_at = NOW()`);

return [{ json: { ruleId: body.ruleId, tenantId: body.tenantId, setClause: sets.join(', ') } }];

parameters.query:
UPDATE email_ai_rules SET {{ $json.setClause }}
WHERE id = '{{ $json.ruleId }}'::uuid AND tenant_id = '{{ $json.tenantId }}'::uuid
RETURNING *
